import{_ as e,c as l,o,a as r}from"./app.bc6903c6.js";const g=JSON.parse('{"title":"系统安装后要做的那些事","description":"","frontmatter":{},"headers":[{"level":2,"title":"一、常用软件","slug":"一、常用软件","link":"#一、常用软件","children":[]},{"level":2,"title":"二、clone git project","slug":"二、clone-git-project","link":"#二、clone-git-project","children":[]},{"level":2,"title":"三、系统部分默认配置","slug":"三、系统部分默认配置","link":"#三、系统部分默认配置","children":[]}],"relativePath":"zh/windows/系统安装初始化.md","lastUpdated":1677552463000}'),t={name:"zh/windows/系统安装初始化.md"},a=r(`<h1 id="系统安装后要做的那些事" tabindex="-1">系统安装后要做的那些事</h1><h2 id="一、常用软件" tabindex="-1">一、常用软件</h2><ol><li><a href="https://chrome.google.com" target="_blank" rel="noreferrer">chrome</a></li></ol><ul><li>打开开发者模式，安装扩展插件 <a href="https://iguge.xyz/" target="_blank" rel="noreferrer">iGG</a>， 同步 chrome 数据</li></ul><ol><li><a href="https://github.com/Fndroid/clash_for_windows_pkg/releases/download/0.20.15/Clash.for.Windows.Setup.0.20.15.exe" target="_blank" rel="noreferrer">clash</a></li></ol><ul><li>打开 chrome 插件 igg ，下载并配置</li></ul><ol start="3"><li><p><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">vscode</a></p></li><li><p><a href="https://developers.weixin.qq.com/miniprogram/dev/devtools/download.html" target="_blank" rel="noreferrer">微信开发者工具</a></p></li><li><p><a href="https://weixin.qq.com/" target="_blank" rel="noreferrer">微信</a></p></li><li><p><a href="https://page.dingtalk.com/wow/z/dingtalk/simple/ddhomedownlaod#/" target="_blank" rel="noreferrer">钉钉</a></p></li><li><p>安装公司内网 vpn (vpn.yaomaitong.cn:4433)</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>先安装自己的 .p12 文件</p></div><ul><li><p>mac：<a href="https://cdnfile.yaomaitong.cn/vpn/anyconnect-macos-4.9.04053.dmg" target="_blank" rel="noreferrer">anyconnect-macos</a>，取消其他选择框，只保留VPN</p></li><li><p>windows：<a href="https://cdnfile.yaomaitong.cn/vpn/anyconnect_win.zip" target="_blank" rel="noreferrer">anyconnect_win.zip</a></p></li><li><p>iphone：首先在AppStore下载App “AnyConnect”</p></li><li><p>android：<a href="https://cdnfile.yaomaitong.cn/vpn/OpenConnect-1.15-1152.apk" target="_blank" rel="noreferrer">OpenConnect.apk</a>，用户认证添加 .p12 文件</p></li></ul><ol start="8"><li><a href="https://dashi.163.com/" target="_blank" rel="noreferrer">网易邮箱大师</a></li><li><a href="https://music.163.com/#/download" target="_blank" rel="noreferrer">网易云音乐</a></li><li><a href="https://github.com/dotnetcore/FastGithub" target="_blank" rel="noreferrer">FastGithub</a></li><li><a href="https://github.com/coreybutler/nvm-windows" target="_blank" rel="noreferrer">nvm</a></li></ol><ul><li>安装 <code>nvm install version</code><ul><li>node 14.17.2</li><li>node 16.14.2</li></ul></li><li>切换node 14.17.2 安装 nrm <code>npm install nrm --save -g</code><ul><li>nrm 切换 taobao 镜像源 <code>nrm current taobao</code></li></ul></li><li>切换node 16.14.2 安装 pnpm <code>npm install pnpm --save -g</code></li></ul><ol start="12"><li><a href="https://www.u.tools/" target="_blank" rel="noreferrer">utools</a></li></ol><ul><li>取消鼠标滚轮键超级面板</li></ul><ol start="13"><li><a href="https://zh.snipaste.com/" target="_blank" rel="noreferrer">snipaste</a></li><li><a href="https://geekuninstaller.com/download" target="_blank" rel="noreferrer">geek</a><ul><li>windows 可用</li></ul></li></ol><ul><li>下载后可拷贝到对应的软件盘中</li></ul><h2 id="二、clone-git-project" tabindex="-1">二、clone git project</h2><p>在 gitea 上克隆常用项目，命名为 project</p><p>在 github 上克隆学习项目，命名为 myproject</p><p>如果是 windows 可以用快捷方式索引到桌面</p><h2 id="三、系统部分默认配置" tabindex="-1">三、系统部分默认配置</h2><ol><li>开机自启动文件夹 C:\\ProgramData\\Microsoft\\Windows\\Start Menu\\Programs\\StartUp</li></ol><ul><li>可以把 utools 和 snipaste 放进来</li></ul><ol start="2"><li>PowerShell因为在此系统中禁止执行脚本解决方法。</li></ol><ul><li>使用 管理员运行 Powershell 执行此命令 <code>set-executionpolicy remotesigned</code></li></ul><ol start="3"><li>安装 wsl</li></ol><ul><li>可参考教程 <a href="https://bbs.huaweicloud.com/blogs/350759" target="_blank" rel="noreferrer">https://bbs.huaweicloud.com/blogs/350759</a> ，重启后，在 Microsoft store 中安装 <a href="https://apps.microsoft.com/store/detail/windows-subsystem-for-linux/9P9TQF7MRM4R" target="_blank" rel="noreferrer">Windows Subsystem for Linux</a></li></ul><ol start="4"><li>Windows PowerShell 美化</li></ol><ul><li><p>在 Microsoft store 中安装 <a href="https://ohmyposh.dev/" target="_blank" rel="noreferrer">Oh My Posh</a>。</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">oh-my-posh init pwsh --config $env:POSH_THEMES_PATH\\M365princess.omp.json | Invoke-Expression</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>复制内容到 <code>code $PROFILE</code> 目录中，注意更换用户名</p><p>字体可以使用 <code>CaskaydiaCove NFM</code></p><p>查看主题 <code>Get-PoshThemes</code></p></li></ul>`,28),n=[a];function i(s,p,c,d,h,m){return o(),l("div",null,n)}const _=e(t,[["render",i]]);export{g as __pageData,_ as default};
